import sys

def is_valid(s, t):
    len_s = len(s)
    len_t = len(t)

    if len_s == len_t:
        return s == t
    elif len_s + 1 == len_t:
        # s could be obtained by deleting one character from t
        i = 0
        j = 0
        while i < len_s and j < len_t:
            if s[i] == t[j]:
                i += 1
                j += 1
            else:
                j += 1
        return i == len_s
    elif len_s - 1 == len_t:
        # t could be obtained by deleting one character from s
        i = 0
        j = 0
        while i < len_t and j < len_s:
            if t[i] == s[j]:
                i += 1
                j += 1
            else:
                j += 1
        return i == len_t
    else:
        return False

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    T_prime = input[1]
    S_list = input[2:]

    result = []
    for idx, s in enumerate(S_list, 1):
        if is_valid(s, T_prime):
            result.append(idx)

    print(len(result))
    if result:
        print(' '.join(map(str, result)))

if __name__ == "__main__":
    main()
